import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { getPatient, getVisits, getHistory, addVisit, addHistory, deleteVisit, deleteHistory } from '../services/api';

const TAB_VISITS = 'visits';
const TAB_HISTORY = 'history';

export default function PatientDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [patient, setPatient] = useState(null);
  const [visits, setVisits] = useState([]);
  const [history, setHistory] = useState([]);
  const [tab, setTab] = useState(TAB_VISITS);
  const [loading, setLoading] = useState(true);
  const [showVisitForm, setShowVisitForm] = useState(false);
  const [showHistoryForm, setShowHistoryForm] = useState(false);
  const [visitForm, setVisitForm] = useState({ visit_date: '', reason: '', diagnosis: '', prescription: '', follow_up_date: '', notes: '' });
  const [histForm, setHistForm] = useState({ condition_name: '', allergies: '', current_medications: '', notes: '' });
  const [saving, setSaving] = useState(false);

  const load = async () => {
    try {
      const [p, v, h] = await Promise.all([getPatient(id), getVisits(id), getHistory(id)]);
      setPatient(p.data.data);
      setVisits(v.data.data);
      setHistory(h.data.data);
    } catch { navigate('/patients'); }
    setLoading(false);
  };

  useEffect(() => { load(); }, [id]);

  const submitVisit = async (e) => {
    e.preventDefault(); setSaving(true);
    await addVisit({ ...visitForm, patient_id: id }).catch(() => {});
    setShowVisitForm(false); setVisitForm({ visit_date: '', reason: '', diagnosis: '', prescription: '', follow_up_date: '', notes: '' });
    await load(); setSaving(false);
  };

  const submitHistory = async (e) => {
    e.preventDefault(); setSaving(true);
    await addHistory({ ...histForm, patient_id: id }).catch(() => {});
    setShowHistoryForm(false); setHistForm({ condition_name: '', allergies: '', current_medications: '', notes: '' });
    await load(); setSaving(false);
  };

  if (loading) return <div style={{ padding: 32, color: '#64748b' }}>Loading...</div>;
  if (!patient) return null;

  const age = Math.floor((new Date() - new Date(patient.dob)) / (365.25 * 24 * 3600 * 1000));
  const vh = e => ({ target: { name: n, value: v } }) => {};

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">{patient.name}</div>
          <div className="page-subtitle">Patient ID #{patient.id} · {age} years · {patient.gender}</div>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <Link to={`/patients/${id}/edit`} className="btn btn-outline">Edit</Link>
          <button onClick={() => navigate('/patients')} className="btn btn-outline">← Back</button>
        </div>
      </div>

      {/* Patient Summary Card */}
      <div className="card" style={{ padding: '20px 24px', marginBottom: 20, display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 20 }}>
        {[
          { label: 'Blood Type', value: patient.blood_type || 'Unknown', highlight: true },
          { label: 'Village', value: patient.village || '—' },
          { label: 'Phone', value: patient.phone || '—' },
          { label: 'Emergency', value: patient.emergency_contact ? `${patient.emergency_contact} (${patient.emergency_phone || '—'})` : '—' },
        ].map(f => (
          <div key={f.label}>
            <div style={{ fontSize: 11, fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 4 }}>{f.label}</div>
            <div style={{ fontSize: 14, fontWeight: f.highlight ? 700 : 500, color: f.highlight ? '#2b7de9' : '#1a202c' }}>{f.value}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: 4, marginBottom: 16 }}>
        {[TAB_VISITS, TAB_HISTORY].map(t => (
          <button key={t} onClick={() => setTab(t)} className="btn" style={{
            background: tab === t ? '#2b7de9' : '#fff', color: tab === t ? '#fff' : '#374151',
            border: '1px solid', borderColor: tab === t ? '#2b7de9' : '#e2e8f0', textTransform: 'capitalize'
          }}>
            {t === TAB_VISITS ? `🩺 Visits (${visits.length})` : `📋 Medical History (${history.length})`}
          </button>
        ))}
      </div>

      {/* Visits Tab */}
      {tab === TAB_VISITS && (
        <div className="card">
          <div style={{ padding: '14px 20px', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ fontWeight: 600, fontSize: 14 }}>Visit Log</div>
            <button className="btn btn-primary btn-sm" onClick={() => setShowVisitForm(true)}>+ Add Visit</button>
          </div>
          {visits.length === 0 ? <div className="empty-state"><div style={{ fontSize: 36 }}>🩺</div><div>No visits recorded yet</div></div> : (
            <div>
              {visits.map(v => (
                <div key={v.id} style={{ padding: '14px 20px', borderBottom: '1px solid #f1f5f9' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 13 }}>{v.reason || 'General Visit'}</div>
                      <div style={{ fontSize: 12, color: '#64748b', marginTop: 2 }}>
                        {v.doctor_name && <span>Dr. {v.doctor_name} · </span>}
                        {new Date(v.visit_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}
                      </div>
                      {v.diagnosis && <div style={{ fontSize: 12, marginTop: 6, color: '#374151' }}>Dx: {v.diagnosis}</div>}
                      {v.prescription && <div style={{ fontSize: 12, color: '#16a34a', marginTop: 2 }}>Rx: {v.prescription}</div>}
                      {v.follow_up_date && <div style={{ fontSize: 12, color: '#f59e0b', marginTop: 2 }}>Follow-up: {new Date(v.follow_up_date).toLocaleDateString('en-IN')}</div>}
                    </div>
                    <button className="btn btn-danger btn-sm" onClick={() => deleteVisit(v.id).then(load)}>Delete</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* History Tab */}
      {tab === TAB_HISTORY && (
        <div className="card">
          <div style={{ padding: '14px 20px', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ fontWeight: 600, fontSize: 14 }}>Medical History</div>
            <button className="btn btn-primary btn-sm" onClick={() => setShowHistoryForm(true)}>+ Add Record</button>
          </div>
          {history.length === 0 ? <div className="empty-state"><div style={{ fontSize: 36 }}>📋</div><div>No history recorded</div></div> : (
            <div>
              {history.map(h => (
                <div key={h.id} style={{ padding: '14px 20px', borderBottom: '1px solid #f1f5f9' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <div>
                      {h.condition_name && <div style={{ fontWeight: 600, fontSize: 13 }}>{h.condition_name}</div>}
                      {h.allergies && <div style={{ fontSize: 12, color: '#e74c3c', marginTop: 4 }}>⚠️ Allergies: {h.allergies}</div>}
                      {h.current_medications && <div style={{ fontSize: 12, color: '#16a34a', marginTop: 4 }}>💊 Medications: {h.current_medications}</div>}
                      {h.notes && <div style={{ fontSize: 12, color: '#64748b', marginTop: 4 }}>Notes: {h.notes}</div>}
                      <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 6 }}>{new Date(h.recorded_at).toLocaleDateString('en-IN')}</div>
                    </div>
                    <button className="btn btn-danger btn-sm" onClick={() => deleteHistory(h.id).then(load)}>Delete</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Add Visit Modal */}
      {showVisitForm && (
        <div className="modal-overlay" onClick={() => setShowVisitForm(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><div style={{ fontWeight: 700 }}>Add Visit</div><button className="btn btn-outline btn-sm" onClick={() => setShowVisitForm(false)}>✕</button></div>
            <form onSubmit={submitVisit}>
              <div className="modal-body">
                <div className="form-grid-2">
                  <div className="form-group"><label>Visit Date *</label><input type="date" value={visitForm.visit_date} onChange={e => setVisitForm(f => ({ ...f, visit_date: e.target.value }))} required /></div>
                  <div className="form-group"><label>Reason</label><input value={visitForm.reason} onChange={e => setVisitForm(f => ({ ...f, reason: e.target.value }))} placeholder="Chief complaint" /></div>
                </div>
                <div className="form-group"><label>Diagnosis</label><input value={visitForm.diagnosis} onChange={e => setVisitForm(f => ({ ...f, diagnosis: e.target.value }))} placeholder="Diagnosis / Findings" /></div>
                <div className="form-group"><label>Prescription</label><textarea value={visitForm.prescription} onChange={e => setVisitForm(f => ({ ...f, prescription: e.target.value }))} rows={2} placeholder="Medicines prescribed" /></div>
                <div className="form-grid-2">
                  <div className="form-group"><label>Follow-up Date</label><input type="date" value={visitForm.follow_up_date} onChange={e => setVisitForm(f => ({ ...f, follow_up_date: e.target.value }))} /></div>
                  <div className="form-group"><label>Notes</label><input value={visitForm.notes} onChange={e => setVisitForm(f => ({ ...f, notes: e.target.value }))} placeholder="Additional notes" /></div>
                </div>
              </div>
              <div className="modal-footer"><button type="button" className="btn btn-outline" onClick={() => setShowVisitForm(false)}>Cancel</button><button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : 'Save Visit'}</button></div>
            </form>
          </div>
        </div>
      )}

      {/* Add History Modal */}
      {showHistoryForm && (
        <div className="modal-overlay" onClick={() => setShowHistoryForm(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header"><div style={{ fontWeight: 700 }}>Add Medical Record</div><button className="btn btn-outline btn-sm" onClick={() => setShowHistoryForm(false)}>✕</button></div>
            <form onSubmit={submitHistory}>
              <div className="modal-body">
                <div className="form-group"><label>Condition</label><input value={histForm.condition_name} onChange={e => setHistForm(f => ({ ...f, condition_name: e.target.value }))} placeholder="e.g. Hypertension, Diabetes" /></div>
                <div className="form-group"><label>Allergies</label><input value={histForm.allergies} onChange={e => setHistForm(f => ({ ...f, allergies: e.target.value }))} placeholder="Known allergies (or None)" /></div>
                <div className="form-group"><label>Current Medications</label><textarea value={histForm.current_medications} onChange={e => setHistForm(f => ({ ...f, current_medications: e.target.value }))} rows={2} placeholder="Ongoing medications" /></div>
                <div className="form-group"><label>Notes</label><textarea value={histForm.notes} onChange={e => setHistForm(f => ({ ...f, notes: e.target.value }))} rows={2} placeholder="Additional notes" /></div>
              </div>
              <div className="modal-footer"><button type="button" className="btn btn-outline" onClick={() => setShowHistoryForm(false)}>Cancel</button><button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : 'Save Record'}</button></div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
